parameters.jsCode:
const texto = $input.first().json.output.mensaje; 

// Contar palabras
const palabras = texto.trim().split(/\s+/).filter(p => p.length > 0);
const totalPalabras = palabras.length;

// Calcular pausa simulando escritura humana
// Promedio humano: ~40 palabras por minuto
const palabrasPorMinuto = 40;
const milisegundosPorPalabra = (60 / palabrasPorMinuto) * 1000; // 1500ms por palabra

// Tiempo base de "pensar antes de responder" (1 a 3 segundos)
const tiempoBase = Math.floor(Math.random() * 2000) + 1000;

// Pequeña variación aleatoria para que no sea robótico (±20%)
const variacion = 1 + (Math.random() * 0.4 - 0.2);

const pausaMs = Math.round((totalPalabras * milisegundosPorPalabra + tiempoBase) * variacion);

// Limite máximo de 15 segundos para no esperar demasiado
const pausaFinal = Math.min(pausaMs, 15000);

// Hacer la pausa
await new Promise(resolve => setTimeout(resolve, pausaFinal));

const nombreCliente = $input.first().json.output.nombreCliente;
const tipoCliente = $input.first().json.output.tipoCliente;
const correo = $input.first().json.output.correo
const telefono= $('Code in JavaScript2').first().json.Telefono;

return [{
  json: {
    texto,
    nombreCliente,
    tipoCliente,
    correo,
    telefono,
    total_palabras: totalPalabras,
    pausa_aplicada_ms: pausaFinal,
    pausa_aplicada_seg: (pausaFinal / 1000).toFixed(2)
  }
}];

// Obtener el valor de remoteJid
const remoteJid = $input.first().json.remoteJid;

// Extraer el número (todo lo que está antes de "@")
const phoneNumber = remoteJid.split('@')[0];

// Devolver el resultado en el formato que espera n8n
return [{
  json: {
    phoneNumber: phoneNumber
  }
}];

const item = $input.first().json;
const fechaContacto = item['Fecha 1er contacto'];

// true si viene null, undefined, vacío o solo espacios
const ClienteNuevo = (
  fechaContacto === null || 
  fechaContacto === undefined || 
  String(fechaContacto).trim() === ''
);

return [{
  json: {
    ...item,
    ClienteNuevo
  }
}];

